import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { PlaceCard } from './components/PlaceCard';
import { PlaceDetailModal } from './components/PlaceDetailModal';
import { OperatorsList } from './components/OperatorsList';
import { TripDashboard } from './components/TripDashboard';
// Added LOGO to imports
import { MOCK_PLACES, MOCK_OPERATORS, LOGO } from './constants';
import { Place, TourOperator, User, SavedItem, PlaceCategory } from './types';
import { X, Mail, Lock, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [user, setUser] = useState<User | null>(null);
  const [activePage, setActivePage] = useState('home'); // home, operators, trips
  const [selectedPlace, setSelectedPlace] = useState<Place | null>(null);
  const [savedItems, setSavedItems] = useState<SavedItem[]>([]);
  const [isAuthOpen, setIsAuthOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [operatorFilter, setOperatorFilter] = useState<string[]>([]);
  const [pendingSaveId, setPendingSaveId] = useState<string | null>(null);

  // Persistence (Simulated DB)
  useEffect(() => {
    const storedItems = localStorage.getItem('places_saved_items');
    if (storedItems) setSavedItems(JSON.parse(storedItems));

    const storedUser = localStorage.getItem('places_user');
    if (storedUser) setUser(JSON.parse(storedUser));
  }, []);

  useEffect(() => {
    localStorage.setItem('places_saved_items', JSON.stringify(savedItems));
  }, [savedItems]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('places_user', JSON.stringify(user));
      // Intent recovery: Check if we had a pending save
      if (pendingSaveId) {
        handleSaveItem(pendingSaveId);
        setPendingSaveId(null);
        setActivePage('trips');
      }
    } else {
      localStorage.removeItem('places_user');
    }
  }, [user, pendingSaveId]);

  // Actions
  const handleLogin = () => {
    // Mock successful login
    const mockUser: User = { id: 'u1', name: 'Juma K.', email: 'juma@kenya.com', role: 'USER' };
    setUser(mockUser);
    setIsAuthOpen(false);
  };

  const handleLogout = () => {
    setUser(null);
    setActivePage('home');
  };

  const handleSaveItem = (placeId: string) => {
    if (!user) {
      setPendingSaveId(placeId);
      setIsAuthOpen(true);
      return;
    }

    if (!savedItems.some(i => i.placeId === placeId)) {
      const newItem: SavedItem = {
        id: Math.random().toString(36).substr(2, 9),
        placeId,
        addedAt: new Date().toISOString()
      };
      setSavedItems(prev => [...prev, newItem]);
    }
  };

  const handleRemoveItem = (id: string) => {
    setSavedItems(prev => prev.filter(i => i.id !== id));
  };

  const openOperatorView = (tags: string[]) => {
    setOperatorFilter(tags);
    setActivePage('operators');
    setSelectedPlace(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // Filtered Lists
  const filteredPlaces = MOCK_PLACES.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    p.location.toLowerCase().includes(searchQuery.toLowerCase()) ||
    p.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  const filteredOperators = operatorFilter.length > 0 
    ? MOCK_OPERATORS.filter(o => o.specialties.some(s => operatorFilter.includes(s)))
    : MOCK_OPERATORS;

  return (
    <div className="min-h-screen bg-navy transition-all duration-500 overflow-x-hidden">
      <Navbar 
        user={user} 
        onLogout={handleLogout} 
        onOpenAuth={() => setIsAuthOpen(true)}
        onNavigate={setActivePage}
        activePage={activePage}
      />

      {/* Main Views */}
      {activePage === 'home' && (
        <main className="animate-fade-in">
          <Hero onSearch={setSearchQuery} />
          <section className="max-w-7xl mx-auto px-4 py-20">
            <div className="flex items-end justify-between mb-12">
              <div className="space-y-4">
                <span className="text-safari font-bold uppercase tracking-widest text-sm">Curated Collection</span>
                <h2 className="text-4xl md:text-5xl font-serif font-bold">Featured Destinations</h2>
              </div>
              <div className="hidden md:flex gap-4">
                {Object.values(PlaceCategory).map(cat => (
                  <button 
                    key={cat}
                    className="px-4 py-2 rounded-full border border-white/10 hover:border-safari hover:text-safari transition-all text-xs font-bold uppercase tracking-tighter"
                  >
                    {cat.replace('_', ' ')}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {filteredPlaces.length > 0 ? (
                filteredPlaces.map(place => (
                  <PlaceCard 
                    key={place.id} 
                    place={place} 
                    onClick={setSelectedPlace} 
                  />
                ))
              ) : (
                <div className="col-span-full py-20 text-center opacity-50">
                   No places found matching your search.
                </div>
              )}
            </div>
          </section>
        </main>
      )}

      {activePage === 'operators' && (
        <main className="max-w-7xl mx-auto px-4 pt-32 animate-fade-in">
          <div className="space-y-4 mb-12">
            <h1 className="text-5xl font-serif font-bold">Tour Operator Directory</h1>
            <p className="text-xl text-white/60">Find the perfect guide or agency for your next adventure.</p>
            {operatorFilter.length > 0 && (
              <div className="flex items-center gap-2 pt-4">
                <span className="text-sm text-white/40">Filtering for:</span>
                {operatorFilter.map(f => (
                  <span key={f} className="bg-safari px-3 py-1 rounded-full text-xs font-bold flex items-center gap-2">
                    {f}
                    <X size={14} className="cursor-pointer" onClick={() => setOperatorFilter(prev => prev.filter(x => x !== f))} />
                  </span>
                ))}
                <button 
                  onClick={() => setOperatorFilter([])}
                  className="text-xs text-white/40 hover:text-white underline"
                >
                  Clear all
                </button>
              </div>
            )}
          </div>
          <OperatorsList operators={filteredOperators} />
        </main>
      )}

      {activePage === 'trips' && user && (
        <TripDashboard 
          savedItems={savedItems} 
          places={MOCK_PLACES} 
          onRemove={handleRemoveItem}
          onNavigateHome={() => setActivePage('home')}
        />
      )}

      {/* Footer */}
      <footer className="bg-black/40 border-t border-white/5 py-12 px-4 text-center mt-20">
        <div className="max-w-7xl mx-auto space-y-8">
          <div className="flex justify-center items-center gap-2 grayscale opacity-50">
            {LOGO}
            <span className="font-serif text-xl font-bold">PlacesInKenya</span>
          </div>
          <p className="text-white/40 text-sm max-w-lg mx-auto leading-relaxed">
            &copy; 2024 PlacesInKenya. Built with love for the Pearl of Africa. All rights reserved. 
            Kenya Connect is now PlacesInKenya.
          </p>
          <div className="flex justify-center gap-8 text-white/30 text-xs font-bold uppercase tracking-widest">
             <a href="#" className="hover:text-safari transition-colors">Privacy Policy</a>
             <a href="#" className="hover:text-safari transition-colors">Terms of Service</a>
             <a href="#" className="hover:text-safari transition-colors">Partner With Us</a>
          </div>
        </div>
      </footer>

      {/* Detail Modal */}
      {selectedPlace && (
        <PlaceDetailModal 
          place={selectedPlace}
          onClose={() => setSelectedPlace(null)}
          onAddToTrip={(p) => handleSaveItem(p.id)}
          onExploreOperators={openOperatorView}
          isSaved={savedItems.some(i => i.placeId === selectedPlace.id)}
        />
      )}

      {/* Auth Modal (Mock) */}
      {isAuthOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={() => setIsAuthOpen(false)}></div>
          <div className="relative glass w-full max-w-md p-10 rounded-3xl shadow-2xl space-y-8">
            <div className="text-center space-y-2">
               <div className="w-16 h-16 bg-safari/20 text-safari flex items-center justify-center rounded-2xl mx-auto mb-4">
                 <ShieldCheck size={32} />
               </div>
               <h2 className="text-3xl font-serif font-bold">Welcome Back</h2>
               <p className="text-white/50">Login to unlock your personal trip planner.</p>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-xs font-bold uppercase tracking-widest text-white/40">Email Address</label>
                <div className="relative">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-white/30" size={18} />
                  <input type="email" placeholder="example@gmail.com" className="w-full bg-white/5 border border-white/10 rounded-xl px-12 py-3 outline-none focus:border-safari transition-colors" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold uppercase tracking-widest text-white/40">Password</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-white/30" size={18} />
                  <input type="password" placeholder="••••••••" className="w-full bg-white/5 border border-white/10 rounded-xl px-12 py-3 outline-none focus:border-safari transition-colors" />
                </div>
              </div>
              <button 
                onClick={handleLogin}
                className="w-full py-4 bg-safari hover:bg-safari-light text-white rounded-xl font-bold text-lg shadow-lg shadow-safari/20 transition-all active:scale-95"
              >
                Sign In
              </button>
            </div>

            <p className="text-center text-sm text-white/40">
              Don't have an account? <span className="text-safari font-bold cursor-pointer">Register</span>
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
